  Get-ChildItem 'C:\Program Files*\1cv8*','C:\Program Files*\1C*','D:\1C*','E:\1C*' -ErrorAction SilentlyContinue | Select-Object FullName
  Get-ChildItem 'C:\Program Files (x86)\1cv8','C:\Program Files\1cv8' -ErrorAction SilentlyContinue | Select-Object Name,FullName

  Write-Output '=== SHARE ACCESS FROM 1C ==='
